    local eventPage = getgenv().AxiomHubUiConstante.New({
        Title = "Event"
    })
    local fairSettings = userSettings.Event["Uhnne Fair"]
    local mazeLasers = {}
    local mazeFolder = nil

    eventPage.Toggle({
